parameters.jsCode:
// 1. Video Slide 1 (Con gancho) desde Github
const urlSlide1Video = $('GitHub slide 1').first().json.secure_url;

// 2. Video Slide 2 (Crudo cortado a 58s) desde CloudConvert
const urlSlide2RawVideo = $('GitHub slide 2 verdadero').first().json.secure_url;

// 3. Imagen Slide 3 (Explicación / Urgencia) desde Github
const urlSlide3Image = $('GitHub slide 2').first().json.content.download_url;

// 4. Imagen Slide 4 (Cierre Vangard) fija
const urlSlide4Image = "https://raw.githubusercontent.com/TU_USUARIO_GITHUB/TU_REPOSITORIO/main/cierre_vangard_definitivo.png";

// 5. Extraemos el Caption directo de DeepSeek
const caption = $('DeepSeek').first().json.output.caption;

// 6. Armamos el paquete maestro en el orden correcto
return [{
  json: {
    carrusel_urls: [
      urlSlide1Video,      // Índex 0
      urlSlide2RawVideo,   // Índex 1
      urlSlide3Image,      // Índex 2
      urlSlide4Image       // Índex 3
    ],
    post_caption: caption
  }
}];

const items = $input.first().json.items || [];
let comentariosLimpios = [];

// Empezamos en el índice 1 (el 0 es el post original)
for (let i = 1; i < items.length; i++) {
    let textoHTML = items[i].description || "";

    // Limpiamos las etiquetas HTML
    let textoLimpio = textoHTML.replace(/<[^>]*>?/gm, '').trim();

    // FILTRO INTELIGENTE:
    // 1. Que exista el texto
    // 2. Que no sea un bot
    // 3. Que no sea un simple enlace de imagen (http)
    // 4. Que tenga más de 20 caracteres (para evitar los "lol", "yes", "u r right")
    if (
        textoLimpio && 
        !textoLimpio.includes('I am a bot') && 
        !textoLimpio.includes('AutoModerator') &&
        !textoLimpio.includes('http') &&
        textoLimpio.length > 20
    ) {
        comentariosLimpios.push(`- "${textoLimpio}"`);
    }

    // Si ya logramos recolectar 5 comentarios sustanciosos, detenemos el ciclo
    if (comentariosLimpios.length >= 5) break;
}

// Pasamos el texto limpio a la siguiente etapa
return {
    contexto_comentarios: comentariosLimpios.length > 0 
        ? comentariosLimpios.join('\n') 
        : "Video generado por IA. Revisa la imagen para más contexto."
};

// 1. Accedemos a la memoria persistente del flujo
const staticData = $getWorkflowStaticData('global');
staticData.videosProcesados = staticData.videosProcesados || [];

// 2. Obtenemos TODOS los elementos que entran al nodo
const items = $input.all();
const itemsNuevos = [];

// 3. Recorremos cada uno de los videos entrantes
for (const item of items) {
    // Extraemos el ID único (guid o link)
    // Usamos ?. para evitar errores si por alguna razón el json viene vacío
    const postId = item.json?.guid || item.json?.link;

    if (!postId) continue; // Si no hay ID, saltamos al siguiente

    // 4. Verificamos si NO lo hemos procesado antes
    if (!staticData.videosProcesados.includes(postId)) {

        // Lo anotamos en la memoria para el futuro
        staticData.videosProcesados.push(postId);

        // Lo agregamos a la lista de videos que van a pasar
        itemsNuevos.push(item);
    }
}

// 5. AUMENTAMOS a 500 para evitar que videos semanales populares se olviden rápido
if (staticData.videosProcesados.length > 500) {
    staticData.videosProcesados = staticData.videosProcesados.slice(-500);
}

// 6. Devolvemos SOLO los items que pasaron el filtro
return itemsNuevos;

// 1. Extraemos el array de URLs que armó el Empaquetador
const urls = $json.carrusel_urls;

// 2. Primera validación: ¿Existe el array y tiene elementos?
if (!Array.isArray(urls) || urls.length === 0) {
    throw new Error("⛔ GUARDIA DE SEGURIDAD: El paquete viene vacío. No se encontraron URLs.");
}

// 3. Segunda validación: ¿Hay algún impostor (null, undefined, texto roto)?
// .some() revisa todos los elementos, sin importar si son 3 o 5.
const tieneErrores = urls.some(url => !url || typeof url !== 'string' || !url.startsWith('http'));

if (tieneErrores) {
    // Si hay un error, mostramos exactamente qué URLs llegaron para facilitar el diagnóstico
    throw new Error(`⛔ GUARDIA DE SEGURIDAD: Se detectó una URL nula, inválida o rota. Publicación abortada.\nContenido del paquete: ${JSON.stringify(urls, null, 2)}`);
}

// 4. Si todo está perfecto, dejamos pasar el JSON intacto hacia Postiz
return $input.item;

